"use client";

import { useId, useMemo, type ReactElement } from "react";
import { FormProvider } from "react-hook-form";
import { cn } from "@/lib/utils";

import { useRegistrationForm } from "./hooks/use-registration-form";
import { mergeRegistrationLabels } from "./parts/labels";
import { EmailField } from "./parts/email-field";
import { PasswordField } from "./parts/password-field";
import { ConsentCheckbox } from "./parts/consent-checkbox";
import { HoneypotField } from "./parts/honeypot-field";
import { OptionalFieldsFieldset } from "./parts/optional-fields-fieldset";
import { StepIndicator } from "./parts/step-indicator";
import { StepShell } from "./parts/step-shell";
import { ServerError } from "./parts/server-error";
import { SuccessScreen } from "./parts/success-screen";
import { SubmitRow } from "./parts/submit-row";
import { SignInLink } from "./parts/sign-in-link";
import { OauthRow } from "./parts/oauth-row";
import { StrengthMeter } from "./parts/strength-meter";
import type { RegistrationForm01Props } from "./types";

import "./registration-form-01.css";

/**
 * Schema-driven sign-up surface — hand-rolled on RHF v7 + zod v4. Two
 * flow variants (single-step / two-step) × two password strategies
 * (password / magic-link) × two densities (compact / default) × optional
 * OAuth row + declarative optional-fields bag + off-screen honeypot.
 *
 * See `docs/procomps/registration-form-01-procomp/` for the GATE 1 +
 * GATE 2 contract and `usage.tsx` (C6) for the consumer guide. The
 * load-bearing public-API surfaces are:
 *
 * 1. The **discriminated submit payload**: `onSubmit` receives one of
 *    three envelope shapes (`stepCompleted: "single" | "step1" | "step2"`).
 *    Consumers MUST switch on the discriminant. Narrowing optional
 *    profile fields as `| undefined` was rejected because it silently
 *    lets naïve destructuring send `undefined` values to backend APIs.
 *
 * 2. The **status mutual-exclusion contract**: if `status` is provided,
 *    internal state is read-only — the component reads `status` as
 *    source of truth and fires `onStatusChange` for observers only.
 *    Mixing the two (passing `status` AND expecting internal
 *    transitions) is a contract violation.
 *
 * 3. The **honeypot two-key duality**: HTML `name="website"` (spam-bait)
 *    + RHF register key `_honeypot` (clean values shape). Off-screen
 *    rendering is load-bearing — `display: none` is bot-detectable.
 */
export function RegistrationForm01(props: RegistrationForm01Props): ReactElement {
  const {
    heading,
    subheading,
    headingAs: HeadingTag = "h2",
    flow = "single-step",
    passwordStrategy = "password",
    density = "default",
    skippableStepTwo = true,
    fields = {},
    passwordPolicy,
    strengthCalculator,
    consent,
    oauthProviders = [],
    oauthIcons,
    onOAuthClick,
    submitButton,
    signInHref,
    errorMessage,
    successMessage,
    status,
    onStatusChange,
    onSubmit,
    labels: labelsOverride,
    className,
    style,
  } = props;

  const headingId = useId();
  const labels = useMemo(
    () => mergeRegistrationLabels(labelsOverride),
    [labelsOverride],
  );

  const {
    form,
    status: effectiveStatus,
    step,
    goBack,
    submit,
    skip,
  } = useRegistrationForm({
    flow,
    passwordStrategy,
    skippableStepTwo,
    fields,
    passwordPolicy,
    consent,
    labels,
    status,
    onStatusChange,
    onSubmit,
  });

  const showStrengthMeter =
    passwordStrategy === "password" &&
    (passwordPolicy?.showStrengthMeter ?? true);
  const showPasswordField = passwordStrategy === "password";
  const showOptionalFields =
    flow === "single-step" ||
    (flow === "two-step" && step === "step2");
  const showStep1Fields =
    flow === "single-step" ||
    (flow === "two-step" && step === "step1");
  const isSubmitting = effectiveStatus === "submitting";
  const isSuccess = effectiveStatus === "success";
  const submitLabel =
    submitButton?.label ?? labels.createAccountLabel;

  if (isSuccess) {
    return (
      <section
        aria-labelledby={heading ? headingId : undefined}
        className={cn(
          "flex w-full flex-col gap-4",
          density === "compact" ? "max-w-sm" : "max-w-md",
          className,
        )}
        style={style}
      >
        {heading ? (
          <HeadingTag
            id={headingId}
            className="text-xl font-semibold text-foreground"
          >
            {heading}
          </HeadingTag>
        ) : null}
        <SuccessScreen
          message={successMessage ?? labels.successDefaultMessage}
        />
      </section>
    );
  }

  return (
    <section
      aria-labelledby={heading ? headingId : undefined}
      className={cn(
        "flex w-full flex-col",
        density === "compact" ? "max-w-sm gap-3" : "max-w-md gap-4",
        className,
      )}
      style={style}
    >
      {heading ? (
        <HeadingTag
          id={headingId}
          className={cn(
            "font-semibold text-foreground",
            density === "compact" ? "text-lg" : "text-xl",
          )}
        >
          {heading}
        </HeadingTag>
      ) : null}
      {subheading ? (
        <p className="-mt-2 text-sm text-muted-foreground">{subheading}</p>
      ) : null}

      {flow === "two-step" ? (
        <StepIndicator
          current={step === "step1" ? 1 : 2}
          total={2}
          labels={labels}
        />
      ) : null}

      {errorMessage ? <ServerError message={errorMessage} /> : null}

      <OauthRow
        providers={oauthProviders}
        icons={oauthIcons}
        labels={labels}
        disabled={isSubmitting}
        onClick={(provider) => onOAuthClick?.({ provider })}
      />

      <FormProvider {...form}>
        <form
          noValidate
          className={cn(
            "flex flex-col",
            density === "compact" ? "gap-3" : "gap-4",
          )}
          onSubmit={(e) => {
            e.preventDefault();
            void submit();
          }}
        >
          <StepShell step={step}>
            {showStep1Fields ? (
              <>
                <EmailField labels={labels} />
                {showPasswordField ? (
                  <PasswordField
                    labels={labels}
                    strengthMeter={
                      showStrengthMeter ? (
                        <StrengthMeter
                          calculator={strengthCalculator}
                          labels={labels}
                        />
                      ) : null
                    }
                  />
                ) : null}
                <ConsentCheckbox consent={consent} labels={labels} />
              </>
            ) : null}
            {showOptionalFields ? (
              <OptionalFieldsFieldset
                fields={fields}
                labels={labels}
                density={density}
              />
            ) : null}
          </StepShell>

          <HoneypotField labels={labels} />

          <SubmitRow
            status={effectiveStatus}
            flow={flow}
            step={step}
            skippableStepTwo={skippableStepTwo}
            submitLabel={submitLabel}
            submitVariant={submitButton?.variant}
            labels={labels}
            onBack={goBack}
            onSkip={() => void skip()}
          />
        </form>
      </FormProvider>

      {signInHref ? (
        <SignInLink href={signInHref} labels={labels} />
      ) : null}
    </section>
  );
}

/**
 * Sealed-folder CSS for the step-shell fade transition. Imported once
 * at the root component (`registration-form-01.tsx`). The fade collapses
 * to a hard 0ms swap under `prefers-reduced-motion: reduce` so a11y
 * tooling isn't disorientated.
 */

@keyframes registration-form-01-step-fade-in {
  from {
    opacity: 0;
    transform: translateY(2px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

[data-registration-form-01-step] {
  animation: registration-form-01-step-fade-in 150ms ease-out both;
}

@media (prefers-reduced-motion: reduce) {
  [data-registration-form-01-step] {
    animation: none;
  }
}

// Component
export { RegistrationForm01 } from "./registration-form-01";

// Public types
export type {
  RegistrationForm01Props,
  RegistrationFormStatus,
  RegistrationSubmitPayload,
  RegistrationStep1Values,
  RegistrationStep2Values,
  RegistrationLabels,
  OAuthProvider,
  OptionalFieldName,
  OptionalFieldConfig,
  StrengthCalculator,
  ButtonVariant,
} from "./types";

// Helpers
export {
  defaultRegistrationLabels,
  mergeRegistrationLabels,
} from "./parts/labels";
export { defaultStrengthCalculator } from "./lib/strength-calculator";
export { OAUTH_PROVIDERS } from "./lib/oauth-providers";

import type { CSSProperties, ReactNode } from "react";

/**
 * Variant of the standard shadcn Button — matches `ButtonProps["variant"]`
 * without taking a runtime dep on the primitive.
 */
export type ButtonVariant =
  | "default"
  | "destructive"
  | "outline"
  | "secondary"
  | "ghost"
  | "link";

/** Built-in OAuth providers the registration form knows about. */
export type OAuthProvider =
  | "google"
  | "github"
  | "apple"
  | "facebook"
  | "microsoft"
  | "x";

/** Optional profile fields the consumer can opt into via the `fields` prop. */
export type OptionalFieldName =
  | "firstName"
  | "lastName"
  | "displayName"
  | "phone"
  | "company";

/**
 * Lifecycle status. Internal state machine by default; mutable via the
 * controlled `status` / `onStatusChange` escape hatch.
 */
export type RegistrationFormStatus =
  | "idle"
  | "submitting"
  | "success"
  | "error";

/**
 * Pluggable password-strength calculator. 0 = empty / unrated. 1–4 =
 * weak / fair / strong / excellent.
 *
 * v0.1 default is the built-in `(length, character-class-count)` heuristic
 * in `lib/strength-calculator.ts`. Consumers with corporate password
 * policies or who want to drop in zxcvbn replace this slot; v0.2 may ship
 * an opt-in zxcvbn adapter that satisfies the same shape.
 */
export type StrengthCalculator = (password: string) => 0 | 1 | 2 | 3 | 4;

/**
 * Field-config entry. `true` = show + optional. `{ required: true }` =
 * show + required. `false` (or omitted key) = hidden.
 */
export type OptionalFieldConfig = boolean | { required: boolean };

// ─── Values ──────────────────────────────────────────────────────────────────

/**
 * Step-1 values. Email + (optional, magic-link drops it) password + consent
 * + honeypot. Always present at the bottom of the values stack regardless
 * of flow.
 *
 * **`password` is statically typed as optional** because the magic-link
 * strategy drops the field entirely. The Zod resolver enforces required
 * at runtime under `passwordStrategy: "password"`; the static type stays
 * permissive to keep one shape across both strategies.
 */
export interface RegistrationStep1Values {
  email: string;
  password?: string;
  consentAccepted: boolean;
  /**
   * Honeypot field value. **Should always be `""`.** A non-empty value
   * means a spam bot filled the off-screen `<input name="website">` —
   * the discriminated payload flag `isHoneypotTripped` reflects this.
   */
  _honeypot: string;
}

/** Step-2 values: step-1 plus the optional profile bag. */
export interface RegistrationStep2Values extends RegistrationStep1Values {
  firstName?: string;
  lastName?: string;
  displayName?: string;
  phone?: string;
  company?: string;
}

/**
 * Discriminated submit-payload envelope.
 *
 * Consumers MUST switch on `stepCompleted` to know whether the optional
 * profile fields are populated. Narrowing optional fields as
 * `string | undefined` was rejected because it silently lets naïve
 * destructuring (`const { firstName, lastName } = payload.values`) send
 * `undefined` values to backend APIs. The envelope forces the discriminant.
 *
 * - `"single"` — `flow: "single-step"`.
 * - `"step1"` — `flow: "two-step"` + user clicked "Skip for now".
 * - `"step2"` — `flow: "two-step"` + user completed step 2.
 */
export type RegistrationSubmitPayload =
  | {
      stepCompleted: "single";
      values: RegistrationStep2Values;
      isHoneypotTripped: boolean;
    }
  | {
      stepCompleted: "step1";
      values: RegistrationStep1Values;
      isHoneypotTripped: boolean;
    }
  | {
      stepCompleted: "step2";
      values: RegistrationStep2Values;
      isHoneypotTripped: boolean;
    };

// ─── Labels (i18n bag) ───────────────────────────────────────────────────────

export interface RegistrationLabels {
  // Field labels + placeholders
  emailLabel: string;
  emailPlaceholder: string;
  passwordLabel: string;
  passwordPlaceholder: string;
  firstNameLabel: string;
  firstNamePlaceholder: string;
  lastNameLabel: string;
  lastNamePlaceholder: string;
  displayNameLabel: string;
  displayNamePlaceholder: string;
  phoneLabel: string;
  phonePlaceholder: string;
  companyLabel: string;
  companyPlaceholder: string;

  // Buttons
  createAccountLabel: string;
  continueLabel: string;
  backLabel: string;
  skipForNowLabel: string;
  signInLabel: string;

  // OAuth
  orContinueWith: string;
  /** Template — `{provider}` interpolated with capitalized provider name. */
  oauthLabelTemplate: string;

  // Step indicator
  /** Template — `{current}` and `{total}` interpolated. */
  stepOf: string;

  // Error messages
  emailRequired: string;
  emailInvalid: string;
  passwordRequired: string;
  /** Template — `{min}` interpolated with the minLength policy value. */
  passwordTooShort: string;
  passwordMissingUppercase: string;
  passwordMissingNumber: string;
  passwordMissingSymbol: string;
  consentRequired: string;

  // Strength meter
  strengthWeak: string;
  strengthFair: string;
  strengthStrong: string;
  strengthExcellent: string;
  /** Template — `{level}` interpolated with the bucketed strength label. */
  strengthLabel: string;

  // Server-error fallback
  serverError: string;

  // Success
  successDefaultMessage: string;

  // sr-only accessibility hints
  passwordToggleShow: string;
  passwordToggleHide: string;
  honeypotLabel: string;
}

// ─── Component props ─────────────────────────────────────────────────────────

export interface RegistrationForm01Props {
  /** Heading rendered above the form. Optional — consumer may render their own. */
  heading?: string;
  /** Subheading below the heading. */
  subheading?: string;
  /** Semantic level for the heading. Defaults to `h2`. */
  headingAs?: "h1" | "h2" | "h3";

  /** Flow shape. Default `"single-step"`. */
  flow?: "single-step" | "two-step";
  /** Password vs magic-link strategy. Default `"password"`. */
  passwordStrategy?: "password" | "magic-link";
  /** Vertical-rhythm density. Default `"default"`. */
  density?: "compact" | "default";
  /**
   * Controls whether step 2 of the two-step flow renders a "Skip for now"
   * button. Default `true`. Ignored when `flow === "single-step"`.
   */
  skippableStepTwo?: boolean;

  /**
   * Optional-fields bag. Each key:
   * - `true` → show + optional
   * - `false` (or omitted key) → hidden
   * - `{ required: true }` → show + required
   */
  fields?: Partial<Record<OptionalFieldName, OptionalFieldConfig>>;

  /**
   * Password validators + strength-meter toggle. Ignored under
   * `passwordStrategy: "magic-link"`.
   */
  passwordPolicy?: {
    /** Default 8. */
    minLength?: number;
    requireUppercase?: boolean;
    requireNumber?: boolean;
    requireSymbol?: boolean;
    /** Default `true`. */
    showStrengthMeter?: boolean;
  };

  /**
   * BYO strength heuristic — v0.1 contract for the v0.2 zxcvbn opt-in.
   * Default is the built-in `(length, character-class-count)` scorer in
   * `lib/strength-calculator.ts`.
   */
  strengthCalculator?: StrengthCalculator;

  /**
   * ToS consent gate. `required: true` blocks submit until checked.
   * `label` accepts a `ReactNode` for inline `<Link>` composition;
   * the `string + href?` convenience overload renders a plain anchor.
   */
  consent: {
    required: boolean;
    label: ReactNode | string;
    /** Only used when `label` is a string. */
    href?: string;
  };

  /**
   * Render OAuth buttons above the email field. Empty array (or omitted)
   * renders no OAuth row and no divider.
   */
  oauthProviders?: ReadonlyArray<OAuthProvider>;
  /** Per-provider icon override slot. Default: text-only buttons. */
  oauthIcons?: Partial<Record<OAuthProvider, ReactNode>>;
  /**
   * Fires on OAuth button click. The component does NOT handle the
   * redirect / SDK call — consumer drives the actual OAuth handshake.
   */
  onOAuthClick?: (args: { provider: OAuthProvider }) => void;

  /**
   * Submit button label + variant override. Defaults:
   * `{ label: "Create account", variant: "default" }`. On step 1 of the
   * two-step flow, label auto-overrides to `"Continue"`.
   */
  submitButton?: { label?: string; variant?: ButtonVariant };

  /**
   * Renders "Already have an account? Sign in" link below the form when
   * provided. Omit to hide the link.
   */
  signInHref?: string;

  /**
   * Controlled server-error message. When set, renders a `role="alert"`
   * banner above the form. Takes display precedence over the internal
   * `error` status fallback.
   */
  errorMessage?: string;
  /**
   * Success-screen content. Renders on `onSubmit` resolving without
   * throwing (default), or on `status === "success"` (controlled).
   */
  successMessage?: ReactNode | string;

  /**
   * Controlled status escape hatch. **Mutual exclusion:** if provided,
   * internal state becomes read-only — the component reads `status` as
   * source of truth and fires `onStatusChange` for observers only. If
   * omitted, internal state owns transitions and `onStatusChange` fires
   * on each one. Mixing the two (passing `status` AND expecting internal
   * transitions) is a contract violation.
   */
  status?: RegistrationFormStatus;
  /** Fires on every status transition (internal or controlled-mode echo). */
  onStatusChange?: (status: RegistrationFormStatus) => void;

  /** Submit handler — receives the discriminated envelope. */
  onSubmit: (payload: RegistrationSubmitPayload) => void | Promise<void>;

  /** Per-string overrides. Falls back to `defaultRegistrationLabels`. */
  labels?: Partial<RegistrationLabels>;

  /** Container className — applied to the outermost wrapper. */
  className?: string;
  /** Container style — applied to the outermost wrapper. */
  style?: CSSProperties;
}

"use client";

import { useId } from "react";
import { useFormContext } from "react-hook-form";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";
import type {
  RegistrationLabels,
  RegistrationStep2Values,
} from "../types";

export interface EmailFieldProps {
  labels: Pick<RegistrationLabels, "emailLabel" | "emailPlaceholder">;
}

/**
 * Email input + label + inline error. ARIA: `aria-describedby` points
 * to the inline-error region; the region carries `role="alert"` only
 * when populated.
 */
export function EmailField({ labels }: EmailFieldProps) {
  const id = useId();
  const errorId = `${id}-error`;
  const {
    register,
    formState: { errors },
  } = useFormContext<RegistrationStep2Values>();
  const error = errors.email?.message;

  return (
    <div className="flex flex-col gap-1.5">
      <Label htmlFor={id}>{labels.emailLabel}</Label>
      <Input
        id={id}
        type="email"
        autoComplete="email"
        placeholder={labels.emailPlaceholder}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? errorId : undefined}
        {...register("email")}
      />
      <p
        id={errorId}
        role={error ? "alert" : undefined}
        className={cn(
          "min-h-5 text-xs",
          error ? "text-destructive" : "text-transparent",
        )}
      >
        {error ?? ""}
      </p>
    </div>
  );
}

"use client";

import { useId, useState, type ReactNode } from "react";
import { useFormContext } from "react-hook-form";
import { Eye, EyeOff } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";
import type {
  RegistrationLabels,
  RegistrationStep2Values,
} from "../types";

export interface PasswordFieldProps {
  labels: Pick<
    RegistrationLabels,
    | "passwordLabel"
    | "passwordPlaceholder"
    | "passwordToggleShow"
    | "passwordToggleHide"
  >;
  /** Optional strength meter slot — passed in from the root component. */
  strengthMeter?: ReactNode;
}

/**
 * Password input + label + inline error + show/hide eye toggle.
 *
 * The toggle is local state (uncontrolled — irrelevant to the form
 * values). `aria-pressed` + `aria-label` are surfaced for SR users so
 * the button state is announced. The strength meter is passed in as a
 * slot from the root component so the password value sub doesn't have
 * to thread the calculator + labels here.
 */
export function PasswordField({
  labels,
  strengthMeter,
}: PasswordFieldProps) {
  const id = useId();
  const errorId = `${id}-error`;
  const [shown, setShown] = useState(false);
  const {
    register,
    formState: { errors },
  } = useFormContext<RegistrationStep2Values>();
  const error = errors.password?.message;

  return (
    <div className="flex flex-col gap-1.5">
      <Label htmlFor={id}>{labels.passwordLabel}</Label>
      <div className="relative">
        <Input
          id={id}
          type={shown ? "text" : "password"}
          autoComplete="new-password"
          placeholder={labels.passwordPlaceholder}
          aria-invalid={error ? true : undefined}
          aria-describedby={error ? errorId : undefined}
          className="pe-10"
          {...register("password")}
        />
        <Button
          type="button"
          variant="ghost"
          size="icon"
          className="absolute inset-e-1 top-1/2 -translate-y-1/2 size-7"
          aria-pressed={shown}
          aria-label={shown ? labels.passwordToggleHide : labels.passwordToggleShow}
          onClick={() => setShown((v) => !v)}
        >
          {shown ? <EyeOff /> : <Eye />}
        </Button>
      </div>
      {strengthMeter}
      <p
        id={errorId}
        role={error ? "alert" : undefined}
        className={cn(
          "min-h-5 text-xs",
          error ? "text-destructive" : "text-transparent",
        )}
      >
        {error ?? ""}
      </p>
    </div>
  );
}

"use client";

import { useId, type ReactNode } from "react";
import { Controller, useFormContext } from "react-hook-form";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";
import type {
  RegistrationLabels,
  RegistrationStep2Values,
} from "../types";

export interface ConsentCheckboxProps {
  consent: {
    required: boolean;
    label: ReactNode | string;
    href?: string;
  };
  labels: Pick<RegistrationLabels, "consentRequired">;
}

/**
 * Consent checkbox + label. Wired via `<Controller>` because the
 * underlying Radix Checkbox is controlled via `checked` / `onCheckedChange`
 * rather than the native `<input type="checkbox">` interface.
 *
 * **F-cross-13 defensive callback shape:** `onCheckedChange` receives
 * `boolean | "indeterminate"` (Radix) or `boolean` (Base UI). The
 * coercion `typeof v === "boolean" ? v : true` widens both backends.
 *
 * Label accepts `ReactNode` for inline `<Link>` composition; the
 * `string + href?` convenience overload renders a plain `<a>`.
 */
export function ConsentCheckbox({
  consent,
  labels,
}: ConsentCheckboxProps) {
  const id = useId();
  const errorId = `${id}-error`;
  const {
    control,
    formState: { errors },
  } = useFormContext<RegistrationStep2Values>();
  const error = errors.consentAccepted?.message;

  const labelNode: ReactNode =
    typeof consent.label === "string" ? (
      consent.href ? (
        <a
          href={consent.href}
          className="underline underline-offset-2 hover:text-foreground"
          rel="noreferrer"
        >
          {consent.label}
        </a>
      ) : (
        consent.label
      )
    ) : (
      consent.label
    );

  return (
    <div className="flex flex-col gap-1.5">
      <div className="flex items-start gap-2">
        <Controller
          control={control}
          name="consentAccepted"
          render={({ field }) => (
            <Checkbox
              id={id}
              checked={!!field.value}
              onCheckedChange={(v) =>
                field.onChange(typeof v === "boolean" ? v : true)
              }
              onBlur={field.onBlur}
              aria-invalid={error ? true : undefined}
              aria-describedby={error ? errorId : undefined}
              aria-required={consent.required ? true : undefined}
            />
          )}
        />
        <Label
          htmlFor={id}
          className="text-sm font-normal leading-snug text-muted-foreground"
        >
          {labelNode}
        </Label>
      </div>
      <p
        id={errorId}
        role={error ? "alert" : undefined}
        className={cn(
          "min-h-5 text-xs",
          error ? "text-destructive" : "text-transparent",
        )}
      >
        {/* Always render the message text for layout stability; opacity
            collapses to transparent when no error so users don't see a
            premature "you must accept" warning at idle. */}
        {error ?? labels.consentRequired}
      </p>
    </div>
  );
}

"use client";

import { useFormContext } from "react-hook-form";
import {
  HONEYPOT_HTML_NAME,
  HONEYPOT_RHF_KEY,
  HONEYPOT_STYLE,
} from "../lib/honeypot";
import type { RegistrationLabels, RegistrationStep2Values } from "../types";

export interface HoneypotFieldProps {
  labels: Pick<RegistrationLabels, "honeypotLabel">;
}

/**
 * Off-screen anti-spam honeypot. **Two non-obvious facts** worth keeping
 * in mind during refactors:
 *
 * 1. The `style` prop uses absolute off-screen position rather than
 *    `display: none`. `display: none` is bot-detectable; serious form-fill
 *    bots skip non-visible fields. The off-screen pattern keeps the field
 *    *rendered* (and fillable by naïve bots) while invisible to real users.
 *
 * 2. **Attribute order matters.** `{...register(HONEYPOT_RHF_KEY)}`
 *    returns `{ name: "_honeypot", onChange, onBlur, ref }`. The
 *    `name={HONEYPOT_HTML_NAME}` override MUST come AFTER the spread,
 *    otherwise React drops the override and the rendered HTML reads
 *    `name="_honeypot"` — defeating the spam-bait. The two-key duality
 *    (HTML name "website" vs RHF key "_honeypot") is intentional:
 *    consumers see `payload.values._honeypot` cleanly without a confusing
 *    `payload.values.website` shape.
 *
 * `aria-hidden="true"` + `tabIndex={-1}` keep the input out of the AT
 * tree and the keyboard tab order.
 */
export function HoneypotField({ labels }: HoneypotFieldProps) {
  const { register } = useFormContext<RegistrationStep2Values>();
  return (
    <input
      type="text"
      autoComplete="off"
      tabIndex={-1}
      aria-hidden="true"
      aria-label={labels.honeypotLabel}
      style={HONEYPOT_STYLE}
      {...register(HONEYPOT_RHF_KEY as never)}
      name={HONEYPOT_HTML_NAME}
    />
  );
}

