"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useForm, type UseFormReturn } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import {
  buildSchema,
  type SchemaLabels,
} from "../lib/build-schema";
import {
  HONEYPOT_RHF_KEY,
  isHoneypotTripped as computeHoneypotTripped,
} from "../lib/honeypot";
import type {
  OptionalFieldConfig,
  OptionalFieldName,
  RegistrationForm01Props,
  RegistrationFormStatus,
  RegistrationLabels,
  RegistrationStep1Values,
  RegistrationStep2Values,
  RegistrationSubmitPayload,
} from "../types";
import { useFormStep, type FormStep } from "./use-form-step";

const DEFAULT_POLICY = {
  minLength: 8,
  requireUppercase: false,
  requireNumber: false,
  requireSymbol: false,
};

export interface UseRegistrationFormArgs {
  flow: "single-step" | "two-step";
  passwordStrategy: "password" | "magic-link";
  skippableStepTwo: boolean;
  fields: Partial<Record<OptionalFieldName, OptionalFieldConfig>>;
  passwordPolicy: RegistrationForm01Props["passwordPolicy"];
  consent: RegistrationForm01Props["consent"];
  labels: RegistrationLabels;
  status?: RegistrationFormStatus;
  onStatusChange?: (status: RegistrationFormStatus) => void;
  onSubmit: (payload: RegistrationSubmitPayload) => void | Promise<void>;
}

export interface UseRegistrationFormReturn {
  form: UseFormReturn<RegistrationStep2Values>;
  status: RegistrationFormStatus;
  step: FormStep;
  /** Step1 → step2 (two-step). Returns whether the transition succeeded. */
  goNext: () => Promise<boolean>;
  /** Step2 → step1 (two-step). */
  goBack: () => void;
  /** Submit the form. Validates first; transitions status; calls onSubmit with the envelope. */
  submit: () => Promise<void>;
  /** Skip-for-now: submit with step-1 values only (`stepCompleted: "step1"`). Two-step + skippable only. */
  skip: () => Promise<void>;
}

/**
 * Substrate hook. Owns the RHF + Zod glue, the status state machine,
 * and the discriminated submit envelope assembly.
 *
 * **Mutual-exclusion contract (Q5 lock):** if `props.status` is provided,
 * the internal `setStatus` is a no-op for the internal state — the
 * component reads `props.status` as source of truth. `onStatusChange`
 * fires on every computed transition regardless (so observers can react
 * to "what the status WOULD be" in controlled mode).
 */
export function useRegistrationForm(
  args: UseRegistrationFormArgs,
): UseRegistrationFormReturn {
  const {
    flow,
    passwordStrategy,
    skippableStepTwo,
    fields,
    passwordPolicy: rawPolicy,
    consent,
    labels,
    status: controlledStatus,
    onStatusChange,
    onSubmit,
  } = args;

  const isControlled = controlledStatus !== undefined;
  const [internalStatus, setInternalStatus] =
    useState<RegistrationFormStatus>("idle");

  // The onStatusChange callback can change identity every render if the
  // consumer passes an inline arrow function. Stable ref keeps our
  // setStatus identity steady so memoized actions don't re-bind every
  // render.
  const onStatusChangeRef = useRef(onStatusChange);
  useEffect(() => {
    onStatusChangeRef.current = onStatusChange;
  }, [onStatusChange]);

  const setStatus = useCallback(
    (next: RegistrationFormStatus) => {
      if (!isControlled) setInternalStatus(next);
      onStatusChangeRef.current?.(next);
    },
    [isControlled],
  );

  const status: RegistrationFormStatus = isControlled
    ? controlledStatus!
    : internalStatus;

  // Normalize the password policy: shipped + un-shipped flags both
  // collapse to the same shape used by build-schema.
  const policy = useMemo(
    () => ({
      minLength: rawPolicy?.minLength ?? DEFAULT_POLICY.minLength,
      requireUppercase:
        rawPolicy?.requireUppercase ?? DEFAULT_POLICY.requireUppercase,
      requireNumber: rawPolicy?.requireNumber ?? DEFAULT_POLICY.requireNumber,
      requireSymbol: rawPolicy?.requireSymbol ?? DEFAULT_POLICY.requireSymbol,
    }),
    [
      rawPolicy?.minLength,
      rawPolicy?.requireUppercase,
      rawPolicy?.requireNumber,
      rawPolicy?.requireSymbol,
    ],
  );

  const schemaLabels = useMemo<SchemaLabels>(
    () => ({
      emailRequired: labels.emailRequired,
      emailInvalid: labels.emailInvalid,
      passwordRequired: labels.passwordRequired,
      passwordTooShort: labels.passwordTooShort,
      passwordMissingUppercase: labels.passwordMissingUppercase,
      passwordMissingNumber: labels.passwordMissingNumber,
      passwordMissingSymbol: labels.passwordMissingSymbol,
      consentRequired: labels.consentRequired,
    }),
    [
      labels.emailRequired,
      labels.emailInvalid,
      labels.passwordRequired,
      labels.passwordTooShort,
      labels.passwordMissingUppercase,
      labels.passwordMissingNumber,
      labels.passwordMissingSymbol,
      labels.consentRequired,
    ],
  );

  const schema = useMemo(
    () =>
      buildSchema({
        passwordStrategy,
        passwordPolicy: policy,
        fields,
        consent: { required: consent.required },
        labels: schemaLabels,
      }),
    [passwordStrategy, policy, fields, consent.required, schemaLabels],
  );

  const form = useForm<RegistrationStep2Values>({
    // The resolver-cast pattern matches json-form's
    // `use-json-form.ts` precedent (RHF / Zod overload disambiguation).
    resolver: zodResolver(schema as never) as never,
    mode: "onSubmit",
    defaultValues: {
      email: "",
      password: passwordStrategy === "password" ? "" : undefined,
      consentAccepted: false,
      [HONEYPOT_RHF_KEY]: "",
    } as RegistrationStep2Values,
  });

  const stepHook = useFormStep({
    enabled: flow === "two-step",
    form,
  });

  const submitInternal = useCallback(
    async (stepCompleted: "single" | "step1" | "step2") => {
      setStatus("submitting");
      try {
        // form.handleSubmit returns a function that runs validation +
        // either the valid handler or the invalid handler. We invoke it
        // inline so the `await onSubmit(...)` happens within the same
        // try/catch.
        let didFire = false;
        await new Promise<void>((resolve, reject) => {
          void form.handleSubmit(
            async (values) => {
              didFire = true;
              const honeypotValue =
                (values as unknown as Record<string, unknown>)[HONEYPOT_RHF_KEY] ?? "";
              const isHoneypotTripped = computeHoneypotTripped(
                String(honeypotValue),
              );
              const payload = buildPayload(
                stepCompleted,
                values,
                isHoneypotTripped,
              );
              try {
                await onSubmit(payload);
                resolve();
              } catch (err) {
                reject(err);
              }
            },
            () => {
              // Invalid handler — validation failed. We don't transition
              // to "error" here (that's reserved for onSubmit-throws);
              // RHF surfaces the per-field errors via formState.
              resolve();
            },
          )();
          if (!didFire) {
            // Edge: handleSubmit may resolve synchronously when there's
            // no async work; the resolve() above covers that.
          }
        });
        if (didFire) setStatus("success");
        else setStatus("idle"); // validation failed; back to idle
      } catch {
        setStatus("error");
      }
    },
    [form, onSubmit, setStatus],
  );

  const submit = useCallback(async () => {
    const stepCompleted: "single" | "step2" =
      flow === "single-step" ? "single" : "step2";
    await submitInternal(stepCompleted);
  }, [flow, submitInternal]);

  const skip = useCallback(async () => {
    if (flow !== "two-step" || !skippableStepTwo) return;
    // Validate step-1 fields only.
    const ok = await form.trigger([
      "email",
      "password",
      "consentAccepted",
    ] as const);
    if (!ok) return;
    setStatus("submitting");
    try {
      const values = form.getValues();
      const honeypotValue =
        (values as unknown as Record<string, unknown>)[HONEYPOT_RHF_KEY] ?? "";
      const isHoneypotTripped = computeHoneypotTripped(String(honeypotValue));
      const step1Values: RegistrationStep1Values = {
        email: values.email,
        password: values.password,
        consentAccepted: values.consentAccepted,
        _honeypot: String(honeypotValue),
      };
      await onSubmit({
        stepCompleted: "step1",
        values: step1Values,
        isHoneypotTripped,
      });
      setStatus("success");
    } catch {
      setStatus("error");
    }
  }, [flow, skippableStepTwo, form, onSubmit, setStatus]);

  return {
    form,
    status,
    step: stepHook.step,
    goNext: stepHook.goNext,
    goBack: stepHook.goBack,
    submit,
    skip,
  };
}

function buildPayload(
  stepCompleted: "single" | "step1" | "step2",
  values: RegistrationStep2Values,
  isHoneypotTripped: boolean,
): RegistrationSubmitPayload {
  if (stepCompleted === "step1") {
    return {
      stepCompleted: "step1",
      values: {
        email: values.email,
        password: values.password,
        consentAccepted: values.consentAccepted,
        _honeypot: values._honeypot,
      },
      isHoneypotTripped,
    };
  }
  return {
    stepCompleted,
    values,
    isHoneypotTripped,
  };
}

"use client";

import { useMemo } from "react";
import { useWatch } from "react-hook-form";
import { defaultStrengthCalculator } from "../lib/strength-calculator";
import type { RegistrationLabels, StrengthCalculator } from "../types";

export type StrengthLabels = Pick<
  RegistrationLabels,
  | "strengthWeak"
  | "strengthFair"
  | "strengthStrong"
  | "strengthExcellent"
  | "strengthLabel"
>;

export interface UseStrengthMeterArgs {
  calculator?: StrengthCalculator;
  labels: StrengthLabels;
}

export interface UseStrengthMeterReturn {
  score: 0 | 1 | 2 | 3 | 4;
  label: string;
}

/**
 * Narrow-deps password-strength hook. Subscribes to the `password` field
 * via RHF's `useWatch({ name })` against the active FormProvider context;
 * re-computes when the password changes. The consumer-supplied
 * `strengthCalculator` is clamped defensively so a buggy BYO heuristic
 * returning out-of-range values can't crash the meter.
 *
 * `label` interpolates `labels.strengthLabel` (`"Strength: {level}"`)
 * with the bucketed `strengthWeak`/`Fair`/`Strong`/`Excellent` text. For
 * score 0 (empty), `label` is the empty string — the meter is rendered
 * but the descriptive text disappears.
 */
export function useStrengthMeter(
  args: UseStrengthMeterArgs,
): UseStrengthMeterReturn {
  const { calculator, labels } = args;
  const password = useWatch({ name: "password" }) as string | undefined;

  return useMemo<UseStrengthMeterReturn>(() => {
    const calc = calculator ?? defaultStrengthCalculator;
    const raw = calc(password ?? "");
    const score = clampScore(raw);
    if (score === 0) return { score, label: "" };
    const levelText =
      score === 1
        ? labels.strengthWeak
        : score === 2
          ? labels.strengthFair
          : score === 3
            ? labels.strengthStrong
            : labels.strengthExcellent;
    return { score, label: labels.strengthLabel.replace("{level}", levelText) };
  }, [calculator, password, labels]);
}

function clampScore(raw: number): 0 | 1 | 2 | 3 | 4 {
  if (raw <= 0) return 0;
  if (raw === 1) return 1;
  if (raw === 2) return 2;
  if (raw === 3) return 3;
  return 4;
}

"use client";

import { useCallback, useMemo, useState } from "react";
import type { UseFormReturn } from "react-hook-form";
import type {
  RegistrationStep1Values,
  RegistrationStep2Values,
} from "../types";

export type FormStep = "step1" | "step2";

export interface UseFormStepArgs {
  /** When `false`, the hook locks step at `"step1"` and goNext/goBack are no-ops. */
  enabled: boolean;
  form: UseFormReturn<RegistrationStep2Values>;
}

export interface UseFormStepReturn {
  step: FormStep;
  /** Validate step-1 fields; advance to step-2 only if valid. Returns whether the transition succeeded. */
  goNext: () => Promise<boolean>;
  goBack: () => void;
}

/**
 * Step-state hook for the two-step flow. Encapsulates:
 *  - `useState<FormStep>("step1")`
 *  - Partial validation of step-1 fields via `form.trigger([...])`
 *  - No-op behavior under `flow === "single-step"` (enabled=false) so the
 *    hook is always called for hook-order stability without affecting
 *    behavior.
 *
 * Step-1 fields = `email`, `password` (when present), `consentAccepted`.
 * Honeypot is NOT in the step-1 trigger list — it's intentionally
 * "validated" at submit time (where we read it for the trip flag) and
 * has no Zod check.
 */
export function useFormStep(args: UseFormStepArgs): UseFormStepReturn {
  const { enabled, form } = args;
  const [step, setStep] = useState<FormStep>("step1");

  const step1Fields = useMemo<
    Array<keyof RegistrationStep1Values>
  >(() => ["email", "password", "consentAccepted"], []);

  const goNext = useCallback(async () => {
    if (!enabled) return false;
    if (step === "step2") return true;
    const ok = await form.trigger(step1Fields);
    if (ok) setStep("step2");
    return ok;
  }, [enabled, step, form, step1Fields]);

  const goBack = useCallback(() => {
    if (!enabled) return;
    setStep("step1");
  }, [enabled]);

  return { step, goNext, goBack };
}

import { z, type ZodTypeAny } from "zod";
import type {
  OptionalFieldConfig,
  OptionalFieldName,
  RegistrationLabels,
} from "../types";

const OPTIONAL_FIELDS: ReadonlyArray<OptionalFieldName> = [
  "firstName",
  "lastName",
  "displayName",
  "phone",
  "company",
];

/**
 * Subset of `RegistrationLabels` carrying the error-message templates the
 * Zod schema bakes in. The hook passes the full merged labels bag; we
 * narrow here to make the function pure-ish.
 */
export type SchemaLabels = Pick<
  RegistrationLabels,
  | "emailRequired"
  | "emailInvalid"
  | "passwordRequired"
  | "passwordTooShort"
  | "passwordMissingUppercase"
  | "passwordMissingNumber"
  | "passwordMissingSymbol"
  | "consentRequired"
>;

export interface BuildSchemaArgs {
  passwordStrategy: "password" | "magic-link";
  passwordPolicy: {
    minLength: number;
    requireUppercase: boolean;
    requireNumber: boolean;
    requireSymbol: boolean;
  };
  fields: Partial<Record<OptionalFieldName, OptionalFieldConfig>>;
  consent: { required: boolean };
  labels: SchemaLabels;
}

/**
 * Build the Zod schema for the whole form (step 1 + step 2 fields).
 *
 * The schema is **single** — step-1 vs step-2 partial validation is
 * driven by `form.trigger(name[])` at the call site in the hook (NOT by
 * swapping schemas). Step-2-only fields are always optional at the type
 * level so the "Skip for now" path can submit with step-1 values alone
 * without tripping a "required" error on the skipped step-2 fields.
 *
 * Field-by-field rules:
 * - `email`: required, valid email format (Zod's `email()` check).
 * - `password`: optional under `magic-link`; under `password`, required
 *   + `minLength` + each policy class check.
 * - `consentAccepted`: required `true` when `consent.required`; otherwise
 *   just `boolean` (no validation).
 * - `_honeypot`: passthrough string. **Never validated** — the honeypot
 *   "trip" semantics live in `isHoneypotTripped()` at the submit handler,
 *   not in the schema. Validating it here would block submission on a
 *   bot fill, which is the WRONG behavior (we want the bot to think it
 *   succeeded).
 * - Optional fields (`firstName` etc.): present in the schema with
 *   `.optional()` if the consumer opted them in via `fields`. If
 *   `{ required: true }` on the optional-field config AND the user
 *   completes step 2, the field is required. The "Skip for now" path
 *   bypasses step-2 validation entirely (see hook).
 */
export function buildSchema(args: BuildSchemaArgs) {
  const { passwordStrategy, passwordPolicy, fields, consent, labels } = args;

  const emailSchema = z
    .string({ message: labels.emailRequired })
    .min(1, labels.emailRequired)
    .email(labels.emailInvalid);

  let passwordSchema: ZodTypeAny;
  if (passwordStrategy === "magic-link") {
    // Field absent at runtime under magic-link. We still register a
    // schema slot for shape stability (`.optional()`) so partial values
    // shapes line up between the two strategies.
    passwordSchema = z.string().optional();
  } else {
    let chain = z
      .string({ message: labels.passwordRequired })
      .min(
        passwordPolicy.minLength,
        labels.passwordTooShort.replace(
          "{min}",
          String(passwordPolicy.minLength),
        ),
      );
    if (passwordPolicy.requireUppercase) {
      chain = chain.refine((s) => /[A-Z]/.test(s), {
        message: labels.passwordMissingUppercase,
      });
    }
    if (passwordPolicy.requireNumber) {
      chain = chain.refine((s) => /[0-9]/.test(s), {
        message: labels.passwordMissingNumber,
      });
    }
    if (passwordPolicy.requireSymbol) {
      chain = chain.refine((s) => /[^A-Za-z0-9]/.test(s), {
        message: labels.passwordMissingSymbol,
      });
    }
    passwordSchema = chain;
  }

  const consentSchema = consent.required
    ? z.literal(true, {
        message: labels.consentRequired,
      })
    : z.boolean();

  const shape: Record<string, ZodTypeAny> = {
    email: emailSchema,
    password: passwordSchema,
    consentAccepted: consentSchema,
    _honeypot: z.string(),
  };

  for (const name of OPTIONAL_FIELDS) {
    const config = fields[name];
    if (config === undefined || config === false) continue;
    const required = config === true ? false : config.required;
    shape[name] = required ? z.string().min(1) : z.string().optional();
  }

  return z.object(shape);
}

import type { CSSProperties } from "react";

/**
 * The rendered HTML `name` attribute on the honeypot input. Tuned to the
 * spam-bait names most form-fill bots target (`url`, `website`,
 * `homepage`); `website` has the broadest hit-rate. **This is NOT the
 * RHF register key** — see `HONEYPOT_RHF_KEY` below.
 */
export const HONEYPOT_HTML_NAME = "website";

/**
 * The RHF register key + values-bag key. The `_` prefix keeps it out of
 * the natural reading order of `payload.values` (consumers see
 * `payload.values._honeypot` and immediately read it as a meta field
 * rather than mistaking it for a real `website` field).
 */
export const HONEYPOT_RHF_KEY = "_honeypot";

/**
 * Off-screen rendering style. **Critical: `display: none` is
 * bot-detectable — bots skip non-visible fields.** The off-screen
 * absolute-position pattern keeps the field rendered (and fillable by
 * a naïve form-fill bot) while invisible to real users.
 *
 * The 1×1 pixel sizing + `overflow: hidden` prevents any focus-ring
 * leakage if the field somehow receives focus. `tabIndex={-1}` (set on
 * the input element, not here) keeps it off keyboard tab order;
 * `aria-hidden="true"` keeps it off the AT tree.
 */
export const HONEYPOT_STYLE: CSSProperties = {
  position: "absolute",
  left: "-9999px",
  top: "auto",
  width: "1px",
  height: "1px",
  overflow: "hidden",
};

/**
 * A real user cannot tab into the honeypot field (tabIndex={-1}) and
 * cannot see it (off-screen), so any non-empty value means a spam bot
 * filled it. The submit handler surfaces this on the payload via
 * `isHoneypotTripped: boolean`.
 */
export function isHoneypotTripped(value: string): boolean {
  return value.length > 0;
}

import type { OAuthProvider } from "../types";

/**
 * Built-in OAuth provider list — the runtime equivalent of the
 * `OAuthProvider` type literal union. Used to validate / iterate
 * consumer-provided `oauthProviders` arrays.
 */
export const OAUTH_PROVIDERS: ReadonlyArray<OAuthProvider> = [
  "google",
  "github",
  "apple",
  "facebook",
  "microsoft",
  "x",
];

/**
 * Per-provider display name. Used by `getOAuthProviderLabel` to
 * interpolate into `labels.oauthLabelTemplate`. Apple's brand guidelines
 * require "Sign in with Apple" specifically — but this component is
 * neutral on the verb (`Continue with` / `Sign up with`), so we surface
 * the capitalized provider name and let `oauthLabelTemplate` carry the
 * verb.
 */
const PROVIDER_DISPLAY_NAMES: Record<OAuthProvider, string> = {
  google: "Google",
  github: "GitHub",
  apple: "Apple",
  facebook: "Facebook",
  microsoft: "Microsoft",
  x: "X",
};

/**
 * Interpolate the provider name into the consumer-overridable template
 * (`labels.oauthLabelTemplate`). Default template is
 * `"Continue with {provider}"` — yields `"Continue with Google"`.
 */
export function getOAuthProviderLabel(
  provider: OAuthProvider,
  template: string,
): string {
  return template.replace("{provider}", PROVIDER_DISPLAY_NAMES[provider]);
}

import type { StrengthCalculator } from "../types";

/**
 * Built-in password-strength heuristic. Returns 0 for an empty string,
 * 1–4 for non-empty inputs based on length + character-class diversity.
 *
 * Algorithm:
 * - length 0 → 0 (empty / unrated)
 * - score = floor(length / 4) + characterClassCount − 1, clamped to [1, 4]
 *   - length 4 contributes +1; length 12 contributes +3
 *   - character classes = { has-lowercase, has-uppercase, has-digit,
 *     has-symbol } — each adds +1
 *   - then subtract 1 so a single-class short password lands at "weak"
 *
 * This is intentionally not a zxcvbn-style dictionary check — that would
 * pull a ~400KB peer dep for marginal value at v0.1. Consumers with
 * corporate password policies (or who want zxcvbn) plug a different
 * calculator via the `strengthCalculator` prop on `<RegistrationForm01>`.
 */
export const defaultStrengthCalculator: StrengthCalculator = (password) => {
  if (!password) return 0;

  let classes = 0;
  if (/[a-z]/.test(password)) classes++;
  if (/[A-Z]/.test(password)) classes++;
  if (/[0-9]/.test(password)) classes++;
  if (/[^A-Za-z0-9]/.test(password)) classes++;

  const lengthScore = Math.floor(password.length / 4);
  const raw = lengthScore + classes - 1;

  if (raw <= 1) return 1;
  if (raw === 2) return 2;
  if (raw === 3) return 3;
  return 4;
};
